import React, { useState } from 'react';
import axios from 'axios';

function QuestionForm({ onSubmit }) {
  const [answers, setAnswers] = useState(Array(8).fill(''));
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  const questions = [
    "¿Por qué estás interesado en este puesto?",
    "¿Qué experiencia previa tienes en roles similares?",
    "¿Cómo manejas situaciones de presión o estrés en el trabajo?",
    "¿Cuál ha sido tu mayor logro profesional y por qué?",
    "¿Qué herramientas o tecnologías dominas que consideras relevantes para este puesto?",
    "¿Cómo manejas el trabajo en equipo y la colaboración?",
    "¿Dónde te ves profesionalmente en cinco años?",
    "¿Qué te motiva a dar lo mejor de ti en un empleo?"
  ];

  const handleInputChange = (index, value) => {
    const newAnswers = [...answers];
    newAnswers[index] = value;
    setAnswers(newAnswers);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError(null);

    if (answers.some(answer => answer.trim() === '')) {
      setError('Por favor, responde todas las preguntas.');
      setLoading(false);
      return;
    }

    const prompt = `
Eres un evaluador experto en selección de personal. A continuación tienes las respuestas de un postulante a una entrevista de trabajo. Analiza la calidad de sus respuestas, su adecuación al puesto, y genera una evaluación general. Sé detallado pero claro.

Respuestas:
${answers.map((res, i) => `${i + 1}. ${res}`).join('\n')}

Devuélveme una evaluación profesional del perfil del candidato.
    `;

    try {
      const response = await axios.post(
        'https://api.openai.com/v1/chat/completions',
        {
          model: 'gpt-4',
          messages: [
            { role: 'system', content: 'Eres un asistente experto en Recursos Humanos.' },
            { role: 'user', content: prompt }
          ],
          temperature: 0.7
        },
        {
          headers: {
            'Content-Type': 'application/json',
            'Authorization': `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`
          }
        }
      );

      const analysis = response.data.choices[0].message.content;
      onSubmit(analysis);
    } catch (err) {
      console.error('Error al llamar a OpenAI', err);
      setError('Error al analizar las respuestas con IA.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <form onSubmit={handleSubmit}>
      {questions.map((question, i) => (
        <div key={i} style={{ marginBottom: '10px' }}>
          <label htmlFor={`answer-${i}`}>{question}</label><br />
          <textarea
            id={`answer-${i}`}
            rows={3}
            style={{ width: '100%', padding: '8px' }}
            onChange={(e) => handleInputChange(i, e.target.value)}
            value={answers[i]}
            required
            disabled={loading}
          />
        </div>
      ))}

      <button type="submit" disabled={loading} style={{ padding: '10px 20px' }}>
        {loading ? 'Evaluando...' : 'Enviar respuestas'}
      </button>

      {error && <p style={{ color: 'red' }}>{error}</p>}
    </form>
  );
}

export default QuestionForm;
